namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class Course
{
    public int Id { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public string DepartmentName { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = string.Empty;
    public string StudentId { get; set; } = string.Empty;
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and civilizations." }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education. She holds a PhD from MIT.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 2, Code = "CS 201", Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures including trees, graphs, hash tables, and algorithm design techniques.", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park specializes in algorithm optimization and has published over 40 research papers.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 3, Code = "CS 301", Title = "Database Systems", Description = "Design and implementation of relational databases, SQL, normalization, and transaction processing.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", InstructorName = "Dr. Maria Lopez", InstructorBio = "Dr. Lopez worked at Oracle for a decade before joining academia. Expert in distributed systems.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false },
            new() { Id = 4, Code = "CS 401", Title = "Machine Learning", Description = "Introduction to machine learning concepts including supervised and unsupervised learning, neural networks, and model evaluation.", Credits = 4, Schedule = "Tue/Thu 1:00–2:15 PM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education. She holds a PhD from MIT.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 5, Code = "MATH 101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions with applications.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Zhang", InstructorBio = "Dr. Zhang is an award-winning educator with expertise in real analysis and applied mathematics.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true },
            new() { Id = 6, Code = "MATH 201", Title = "Linear Algebra", Description = "Vectors, matrices, linear transformations, eigenvalues, and applications to data science.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", InstructorName = "Dr. Emily Foster", InstructorBio = "Dr. Foster's research focuses on computational linear algebra and numerical methods.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 7, Code = "MATH 301", Title = "Probability and Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Dr. Robert Zhang", InstructorBio = "Dr. Zhang is an award-winning educator with expertise in real analysis and applied mathematics.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 8, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes laboratory component.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Lab Thu 2:00–4:00 PM", InstructorName = "Dr. Alan Reeves", InstructorBio = "Dr. Reeves is a former NASA researcher specializing in astrophysics and mechanics.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = false },
            new() { Id = 9, Code = "PHYS 201", Title = "Electromagnetism", Description = "Electric fields, magnetic fields, Maxwell's equations, and electromagnetic waves.", Credits = 4, Schedule = "Tue/Thu 11:00 AM–12:15 PM", InstructorName = "Dr. Nina Patel", InstructorBio = "Dr. Patel researches quantum electrodynamics and has authored two textbooks on the subject.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = true },
            new() { Id = 10, Code = "ENG 101", Title = "English Composition", Description = "Develop critical reading, thinking, and writing skills through essays and research papers.", Credits = 3, Schedule = "Mon/Wed 10:00–11:15 AM", InstructorName = "Prof. David Kim", InstructorBio = "Prof. Kim is a published novelist and has taught creative and academic writing for 20 years.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
            new() { Id = 11, Code = "ENG 205", Title = "American Literature", Description = "Survey of American literary works from the colonial period to the present.", Credits = 3, Schedule = "Tue/Thu 2:00–3:15 PM", InstructorName = "Dr. Rachel Adams", InstructorBio = "Dr. Adams specializes in 20th-century American fiction and has won multiple teaching awards.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
            new() { Id = 12, Code = "HIST 101", Title = "World History I", Description = "Survey of world civilizations from ancient times through the Renaissance.", Credits = 3, Schedule = "Mon/Wed/Fri 2:00–2:50 PM", InstructorName = "Dr. Thomas Grant", InstructorBio = "Dr. Grant is a historian specializing in ancient civilizations and medieval Europe.", DepartmentId = 5, DepartmentName = "History", IsFeatured = false },
            new() { Id = 13, Code = "HIST 202", Title = "Modern World History", Description = "Major events and developments from the Enlightenment to the present day.", Credits = 3, Schedule = "Tue/Thu 3:30–4:45 PM", InstructorName = "Dr. Lisa Moreno", InstructorBio = "Dr. Moreno's research covers 20th-century geopolitics and social movements.", DepartmentId = 5, DepartmentName = "History", IsFeatured = true }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? searchTerm = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real app this would persist to a database
        return !string.IsNullOrWhiteSpace(request.StudentName)
            && !string.IsNullOrWhiteSpace(request.StudentId)
            && request.CourseId > 0;
    }
}

