@page "/"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<div class="hero">
    <h1>University Course Catalog</h1>
    <p class="lead">Explore departments, discover courses, and enroll for the upcoming semester.</p>
    <a href="/courses" class="btn btn-primary btn-lg">Browse All Courses</a>
</div>

<section class="mt-5">
    <h2>Featured Courses</h2>
    <div class="row mt-3">
        @foreach (var course in featuredCourses)
        {
            <div class="col-md-4 mb-4">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@course.Code</h5>
                        <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                        <p class="card-text">@course.Credits credits &bull; @course.DepartmentName</p>
                        <a href="/courses/@course.Id" class="btn btn-outline-primary btn-sm">View Details</a>
                    </div>
                </div>
            </div>
        }
    </div>
</section>

<section class="mt-5">
    <h2>Departments</h2>
    <div class="row mt-3">
        @foreach (var dept in departments)
        {
            <div class="col-md-4 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">@dept.Name</h5>
                        <p class="card-text text-muted">@dept.Description</p>
                        <a href="/courses?departmentId=@dept.Id" class="btn btn-outline-secondary btn-sm">View Courses</a>
                    </div>
                </div>
            </div>
        }
    </div>
</section>

@code {
    private List<Course> featuredCourses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        featuredCourses = CatalogService.GetFeaturedCourses();
        departments = CatalogService.GetDepartments();
    }
}

@page "/courses"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@rendermode InteractiveServer
@inject CatalogService CatalogService
@inject NavigationManager Navigation

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by title, code, or instructor..."
               @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="selectedDepartmentId">
            <option value="0">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id">@dept.Name</option>
            }
        </select>
    </div>
</div>

@if (filteredCourses.Any())
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Department</th>
                    <th>Credits</th>
                    <th>Instructor</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in filteredCourses)
                {
                    <tr>
                        <td>@course.Code</td>
                        <td>@course.Title</td>
                        <td>@course.DepartmentName</td>
                        <td>@course.Credits</td>
                        <td>@course.InstructorName</td>
                        <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}
else
{
    <p class="text-muted">No courses match your search criteria.</p>
}

@code {
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<Department> departments = new();
    private List<Course> filteredCourses = new();
    private string _searchTerm = string.Empty;
    private int _selectedDepartmentId;

    private string searchTerm
    {
        get => _searchTerm;
        set { _searchTerm = value; FilterCourses(); }
    }

    private int selectedDepartmentId
    {
        get => _selectedDepartmentId;
        set { _selectedDepartmentId = value; FilterCourses(); }
    }

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        _selectedDepartmentId = DepartmentId ?? 0;
        FilterCourses();
    }

    private void FilterCourses()
    {
        int? deptFilter = _selectedDepartmentId > 0 ? _selectedDepartmentId : null;
        filteredCourses = CatalogService.GetCourses(searchTerm, deptFilter);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit this form to request enrollment in a course. You will receive a confirmation via email.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted</h4>
        <p>Thank you, <strong>@request.StudentName</strong>. Your enrollment request for <strong>@selectedCourseTitle</strong> has been received.</p>
        <a href="/courses" class="btn btn-primary">Back to Catalog</a>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-6">
            <form method="post" @onsubmit="HandleSubmit" @formname="enrollment">
                <AntiforgeryToken />
                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <input type="text" class="form-control" id="studentName" name="StudentName"
                           @bind="request.StudentName" required />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <input type="text" class="form-control" id="studentId" name="StudentId"
                           @bind="request.StudentId" required />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <select class="form-select" id="courseId" name="CourseId"
                            @bind="request.CourseId" required>
                        <option value="0" disabled>Select a course...</option>
                        @foreach (var course in courses)
                        {
                            <option value="@course.Id">@course.Code — @course.Title</option>
                        }
                    </select>
                </div>

                @if (!string.IsNullOrEmpty(errorMessage))
                {
                    <div class="alert alert-danger">@errorMessage</div>
                }

                <button type="submit" class="btn btn-success">Submit Request</button>
                <a href="/courses" class="btn btn-outline-secondary ms-2">Cancel</a>
            </form>
        </div>
    </div>
}

@code {
    [SupplyParameterFromQuery] public int? CourseId { get; set; }
    [SupplyParameterFromForm] private EnrollmentRequest request { get; set; } = new();

    private List<Course> courses = new();
    private bool submitted;
    private string errorMessage = string.Empty;
    private string selectedCourseTitle = string.Empty;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses();
        if (CourseId.HasValue && request.CourseId == 0)
        {
            request.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(request.StudentName) ||
            string.IsNullOrWhiteSpace(request.StudentId) ||
            request.CourseId == 0)
        {
            errorMessage = "Please fill in all fields.";
            return;
        }

        var success = CatalogService.SubmitEnrollmentRequest(request);
        if (success)
        {
            var course = CatalogService.GetCourse(request.CourseId);
            selectedCourseTitle = course != null ? $"{course.Code} — {course.Title}" : "Unknown Course";
            submitted = true;
        }
        else
        {
            errorMessage = "There was an error processing your request. Please try again.";
        }
    }
}

