@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit this form to request enrollment in a course. You will receive a confirmation via email.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted</h4>
        <p>Thank you, <strong>@request.StudentName</strong>. Your enrollment request for <strong>@selectedCourseTitle</strong> has been received.</p>
        <a href="/courses" class="btn btn-primary">Back to Catalog</a>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-6">
            <form method="post" @onsubmit="HandleSubmit" @formname="enrollment">
                <AntiforgeryToken />
                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <input type="text" class="form-control" id="studentName" name="StudentName"
                           @bind="request.StudentName" required />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <input type="text" class="form-control" id="studentId" name="StudentId"
                           @bind="request.StudentId" required />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <select class="form-select" id="courseId" name="CourseId"
                            @bind="request.CourseId" required>
                        <option value="0" disabled>Select a course...</option>
                        @foreach (var course in courses)
                        {
                            <option value="@course.Id">@course.Code — @course.Title</option>
                        }
                    </select>
                </div>

                @if (!string.IsNullOrEmpty(errorMessage))
                {
                    <div class="alert alert-danger">@errorMessage</div>
                }

                <button type="submit" class="btn btn-success">Submit Request</button>
                <a href="/courses" class="btn btn-outline-secondary ms-2">Cancel</a>
            </form>
        </div>
    </div>
}

@code {
    [SupplyParameterFromQuery] public int? CourseId { get; set; }
    [SupplyParameterFromForm] private EnrollmentRequest request { get; set; } = new();

    private List<Course> courses = new();
    private bool submitted;
    private string errorMessage = string.Empty;
    private string selectedCourseTitle = string.Empty;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses();
        if (CourseId.HasValue && request.CourseId == 0)
        {
            request.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(request.StudentName) ||
            string.IsNullOrWhiteSpace(request.StudentId) ||
            request.CourseId == 0)
        {
            errorMessage = "Please fill in all fields.";
            return;
        }

        var success = CatalogService.SubmitEnrollmentRequest(request);
        if (success)
        {
            var course = CatalogService.GetCourse(request.CourseId);
            selectedCourseTitle = course != null ? $"{course.Code} — {course.Title}" : "Unknown Course";
            submitted = true;
        }
        else
        {
            errorMessage = "There was an error processing your request. Please try again.";
        }
    }
}
